import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.C_Knpfj2.js";const u=JSON.parse('{"title":"How AOSC Works","description":"","frontmatter":{"aside":false},"headers":[],"relativePath":"how-it-works.md","filePath":"how-it-works.md","lastUpdated":1781637126000}'),s={name:"how-it-works.md"};function i(n,e,c,l,d,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="how-aosc-works" tabindex="-1">How AOSC Works <a class="header-anchor" href="#how-aosc-works" aria-label="Permalink to &quot;How AOSC Works&quot;">​</a></h1><p>AOSC keeps the source index live while it builds a target index in the background. The only planned application-visible interruption is the cutover window, when source writes are briefly blocked so workers can replay the final operations and the coordinator can swap the alias.</p><p>The walkthrough below shows the successful path and maps each step to the <code>_status</code> fields operators see during a migration.</p><div class="tip custom-block"><p class="custom-block-title">Start here</p><p>Use this page when you want the mental model before reading API details. The simulator follows one successful migration and keeps the source, target, alias, coordinator, and shard worker states visible together.</p></div><div id="sm-viz"></div><h2 id="what-to-notice" tabindex="-1">What to Notice <a class="header-anchor" href="#what-to-notice" aria-label="Permalink to &quot;What to Notice&quot;">​</a></h2><ul><li>Source writes continue through backfill, replay, convergence, and target preparation.</li><li>Source-primary shard workers advance independently; a slow shard can hold the migration before cutover.</li><li>The alias continues to point at the source until the coordinator reaches <code>COMPLETING</code>.</li><li>Source writes are blocked during <code>CUTTING_OVER</code>, <code>CATCHING_UP</code>, and alias swap.</li><li>Cancellation and failure can interrupt any non-terminal coordinator or shard phase.</li></ul><div class="warning custom-block"><p class="custom-block-title">Cutover window</p><p>The source write block is intentional. Applications must retry rejected writes during cutover; AOSC is designed to make that window short, not to make it disappear.</p></div><details class="details custom-block"><summary>Status fields behind the simulator</summary><p>The highlighted coordinator and shard phases correspond to fields returned by the <code>_status</code> API. The visual is explanatory, but the phase names come from the plugin state machine so operators can map the animation back to production status output.</p></details><p>For exact phase names and transition diagrams, see <a href="./reference/state-machine">State Machine Reference</a>. For a copy-paste local run, see <a href="./get-started/your-first-migration">Your First Migration</a>.</p>',10)])])}const m=t(s,[["render",i]]);export{u as __pageData,m as default};
